// Result-type convention + structured logger
const { logger } = require('../lib/logger');
function createUser(input) {
  if (!input.email) {
    logger.warn('createUser.invalid', { reason: 'missing email' });
    return { ok: false, error: 'EMAIL_REQUIRED' };
  }
  return { ok: true, value: { id: 1, email: input.email } };
}
module.exports = { createUser };

